DROP TABLE IF EXISTS student_performance;

CREATE TABLE student_performance (
    id INT PRIMARY KEY,
    school VARCHAR(10),
    sex VARCHAR(5),
    age INT,
    address VARCHAR(5),
    famsize VARCHAR(10),
    Pstatus VARCHAR(5),
    Medu INT,
    Fedu INT,
    Mjob VARCHAR(30),
    Fjob VARCHAR(30),
    reason VARCHAR(30),
    guardian VARCHAR(20),
    traveltime INT,
    studytime INT,
    failures INT,
    schoolsup VARCHAR(5),
    famsup VARCHAR(5),
    paid VARCHAR(5),
    activities VARCHAR(5),
    nursery VARCHAR(5),
    higher VARCHAR(5),
    internet VARCHAR(5),
    romantic VARCHAR(5),
    famrel INT,
    freetime INT,
    goout INT,
    Dalc INT,
    Walc INT,
    health INT,
    absences INT,
    G1 INT,
    G2 INT,
    G3 INT
);

